insert into players (team_id, full_name, position, shirt_number, source_url, is_active)
select t.id, s.full_name, s.position::player_position, s.shirt_number, s.source_url, true
from source s
join teams t on t.code = s.team_code
on conflict (team_id, full_name) do update set
  position = excluded.position,
  shirt_number = excluded.shirt_number,
  source_url = excluded.source_url,
  is_active = true;
